import scala.collection.mutable.{HashMap, TreeSet}

class DSU(val c: Int) {
  val parent: Array[Int] = Array.fill(c + 1)(0)
  val rank: Array[Int] = Array.fill(c + 1)(0)

  def init(): Unit = {
    for (i <- 1 to c) {
      parent(i) = i
      rank(i) = 1
    }
  }

  def find(x: Int): Int = {
    if (parent(x) != x) parent(x) = find(parent(x))
    parent(x)
  }

  def union(x: Int, y: Int): Unit = {
    val rootX = find(x)
    val rootY = find(y)
    if (rootX != rootY) {
      if (rank(rootX) > rank(rootY)) {
        parent(rootY) = rootX
      } else {
        parent(rootX) = rootY
        if (rank(rootX) == rank(rootY)) rank(rootY) += 1
      }
    }
  }
}

def solve(c: Long, connections: Array[Array[Long]], queries: Array[Array[Long]]): Array[Long] = {
  val dsu = new DSU(c.toInt)
  dsu.init()
  for (conn <- connections) {
    val u = conn(0).toInt
    val v = conn(1).toInt
    dsu.union(u, v)
  }

  val rootToStations = HashMap[Long, TreeSet[Long]]()
  for (station <- 1 to c.toInt) {
    val root = dsu.find(station)
    if (!rootToStations.contains(root)) {
      rootToStations(root) = TreeSet[Long]()
    }
    rootToStations(root) += station
  }

  val result = scala.collection.mutable.ArrayBuffer[Long]()

  for (query <- queries) {
    val typeQuery = query(0)
    val x = query(1).toInt
    if (typeQuery == 1) {
      val root = dsu.find(x)
      val stations = rootToStations(root)
      if (stations.contains(x)) {
        result += x.toLong
      } else {
        if (stations.nonEmpty) {
          result += stations.head.toLong
        } else {
          result += -1.toLong
        }
      }
    } else {
      val root = dsu.find(x)
      val stations = rootToStations(root)
      stations.remove(x)
    }
  }

  result.toArray
}
